select v_1 as "c_custkey", v_2 as "c_name", v_3 as "c_acctbal", v_4 as "c_phone", v_5 as "n_name", v_6 as "c_address", v_7 as "c_comment", v_8 as "revenue" from (select v_9 as v_1, v_10 as v_2, v_11 as v_3, v_12 as v_4, v_13 as v_5, v_14 as v_6, v_15 as v_7, sum(v_16 * (1 - v_17)) as v_8 from (select * from (select * from (select * from (select * from (select "o_orderkey" as v_18, "o_custkey" as v_19, "o_orderstatus" as v_20, "o_totalprice" as v_21, "o_orderdate" as v_22, "o_orderpriority" as v_23, "o_clerk" as v_24, "o_shippriority" as v_25, "o_comment" as v_26 from "orders") s where (v_22 >= (date('1993-10-01', '+0 seconds'))) and (v_22 < (date('1993-10-01', '+3 months')))) l inner join (select "c_custkey" as v_9, "c_name" as v_10, "c_address" as v_14, "c_nationkey" as v_27, "c_phone" as v_12, "c_acctbal" as v_11, "c_mktsegment" as v_28, "c_comment" as v_15 from "customer") r on v_9 = v_19) l inner join (select * from (select "l_orderkey" as v_29, "l_partkey" as v_30, "l_suppkey" as v_31, "l_linenumber" as v_32, "l_quantity" as v_33, "l_extendedprice" as v_16, "l_discount" as v_17, "l_tax" as v_34, "l_returnflag" as v_35, "l_linestatus" as v_36, "l_shipdate" as v_37, "l_commitdate" as v_38, "l_receiptdate" as v_39, "l_shipinstruct" as v_40, "l_shipmode" as v_41, "l_comment" as v_42 from "lineitem") s where v_35 = 'R') r on v_29 = v_18) l inner join (select "n_nationkey" as v_43, "n_name" as v_13, "n_regionkey" as v_44, "n_comment" as v_45 from "nation") r on v_27 = v_43) s group by 1, 2, 3, 4, 5, 6, 7) s order by v_8 desc limit 20
